// --- File: CartManager.swift ---

import Foundation

class CartManager {
    static let shared = CartManager()
    
    private(set) var items: [CartItem] = []
    
    var totalInCents: Int {
        items.reduce(0) { $0 + ($1.service.priceInCents * $1.quantity) }
    }
    
    var formattedTotal: String {
        let dollars = Double(totalInCents) / 100.0
        return String(format: "$%.2f", dollars)
    }
    
    var itemCount: Int {
        items.reduce(0) { $0 + $1.quantity }
    }
    
    func addItem(_ service: ServiceLocation) {
        if let index = items.firstIndex(where: { $0.service.id == service.id }) {
            items[index].quantity += 1
        } else {
            items.append(CartItem(service: service, quantity: 1))
        }
        NotificationCenter.default.post(name: .cartUpdated, object: nil)
    }
    
    func removeItem(_ service: ServiceLocation) {
        if let index = items.firstIndex(where: { $0.service.id == service.id }) {
            items[index].quantity -= 1
            if items[index].quantity <= 0 {
                items.remove(at: index)
            }
        }
        NotificationCenter.default.post(name: .cartUpdated, object: nil)
    }
    
    func clearCart() {
        items.removeAll()
        NotificationCenter.default.post(name: .cartUpdated, object: nil)
    }
}

extension Notification.Name {
    static let cartUpdated = Notification.Name("cartUpdated")
}


