import UIKit
import GoogleMaps

class MapViewController: UIViewController, GMSMapViewDelegate {
    
    private var mapView: GMSMapView!
    private var services = DemoData.services
    private let infoPanel = UIView()
    private let infoPanelStack = UIStackView()
    private var selectedService: ServiceLocation?
    private var infoPanelBottomConstraint: NSLayoutConstraint!
    
    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Explore Map"
        view.backgroundColor = .systemBackground
        
        setupMap()
        setupInfoPanel()
        addMarkers()
        setupFilterBar()
    }
    
    private func setupMap() {
        let camera = GMSCameraPosition.camera(
            withLatitude: 37.7900,
            longitude: -122.4150,
            zoom: 13.0
        )
        
        let options = GMSMapViewOptions()
        options.camera = camera
        options.frame = view.bounds
        
        mapView = GMSMapView(options: options)
        mapView.autoresizingMask = [.flexibleWidth, .flexibleHeight]
        mapView.delegate = self
        mapView.isMyLocationEnabled = true
        mapView.settings.myLocationButton = true
        mapView.settings.compassButton = true
        mapView.settings.zoomGestures = true
        
        // Apply a clean style
        mapView.mapStyle = try? GMSMapStyle(jsonString: mapStyleJSON)
        
        view.addSubview(mapView)
    }
    
    private func setupFilterBar() {
        let filterScroll = UIScrollView()
        filterScroll.showsHorizontalScrollIndicator = false
        filterScroll.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(filterScroll)
        
        let filterStack = UIStackView()
        filterStack.axis = .horizontal
        filterStack.spacing = 8
        filterStack.translatesAutoresizingMaskIntoConstraints = false
        filterScroll.addSubview(filterStack)
        
        // "All" button
        let allButton = createFilterButton(title: "All", color: .systemGray, isSelected: true)
        allButton.tag = -1
        allButton.addTarget(self, action: #selector(filterTapped(_:)), for: .touchUpInside)
        filterStack.addArrangedSubview(allButton)
        
        for (index, category) in ServiceCategory.allCases.enumerated() {
            let button = createFilterButton(
                title: "\(category.iconName.prefix(0))\(category.rawValue)",
                color: category.color,
                isSelected: false
            )
            button.tag = index
            button.addTarget(self, action: #selector(filterTapped(_:)), for: .touchUpInside)
            filterStack.addArrangedSubview(button)
        }
        
        NSLayoutConstraint.activate([
            filterScroll.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor, constant: 8),
            filterScroll.leadingAnchor.constraint(equalTo: view.leadingAnchor, constant: 8),
            filterScroll.trailingAnchor.constraint(equalTo: view.trailingAnchor, constant: -8),
            filterScroll.heightAnchor.constraint(equalToConstant: 44),
            
            filterStack.topAnchor.constraint(equalTo: filterScroll.topAnchor),
            filterStack.leadingAnchor.constraint(equalTo: filterScroll.leadingAnchor),
            filterStack.trailingAnchor.constraint(equalTo: filterScroll.trailingAnchor),
            filterStack.bottomAnchor.constraint(equalTo: filterScroll.bottomAnchor),
            filterStack.heightAnchor.constraint(equalTo: filterScroll.heightAnchor)
        ])
    }
    
    private func createFilterButton(title: String, color: UIColor, isSelected: Bool) -> UIButton {
        let button = UIButton(type: .system)
        button.setTitle(title, for: .normal)
        button.titleLabel?.font = .systemFont(ofSize: 13, weight: .semibold)
        button.setTitleColor(isSelected ? .white : color, for: .normal)
        button.backgroundColor = isSelected ? color : color.withAlphaComponent(0.1)
        button.layer.cornerRadius = 18
        button.contentEdgeInsets = UIEdgeInsets(top: 8, left: 16, bottom: 8, right: 16)
        return button
    }
    
    @objc private func filterTapped(_ sender: UIButton) {
        // Update button appearances
        if let filterScroll = sender.superview?.superview as? UIScrollView,
           let filterStack = filterScroll.subviews.first as? UIStackView {
            for case let button as UIButton in filterStack.arrangedSubviews {
                let idx = button.tag
                let color: UIColor
                if idx == -1 {
                    color = .systemGray
                } else {
                    color = ServiceCategory.allCases[idx].color
                }
                let isSelected = button == sender
                button.setTitleColor(isSelected ? .white : color, for: .normal)
                button.backgroundColor = isSelected ? color : color.withAlphaComponent(0.1)
            }
        }
        
        if sender.tag == -1 {
            services = DemoData.services
        } else {
            let category = ServiceCategory.allCases[sender.tag]
            services = DemoData.services.filter { $0.category == category }
        }
        
        mapView.clear()
        addMarkers()
        hideInfoPanel()
    }
    
    private func addMarkers() {
        for service in services {
            let marker = GMSMarker(position: service.coordinate)
            marker.title = service.name
            marker.snippet = "\(service.formattedPrice) • ⭐ \(service.rating)"
            marker.icon = GMSMarker.markerImage(with: service.category.color)
            marker.userData = service
            marker.map = mapView
            
            // Add a subtle animation
            marker.appearAnimation = .pop
        }
    }
    
    private func setupInfoPanel() {
        infoPanel.backgroundColor = .systemBackground
        infoPanel.layer.cornerRadius = 20
        infoPanel.layer.maskedCorners = [.layerMinXMinYCorner, .layerMaxXMinYCorner]
        infoPanel.layer.shadowColor = UIColor.black.cgColor
        infoPanel.layer.shadowOpacity = 0.15
        infoPanel.layer.shadowOffset = CGSize(width: 0, height: -4)
        infoPanel.layer.shadowRadius = 12
        infoPanel.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(infoPanel)
        
        infoPanelStack.axis = .vertical
        infoPanelStack.spacing = 12
        infoPanelStack.translatesAutoresizingMaskIntoConstraints = false
        infoPanel.addSubview(infoPanelStack)
        
        infoPanelBottomConstraint = infoPanel.bottomAnchor.constraint(
            equalTo: view.bottomAnchor, constant: 300
        )
        
        NSLayoutConstraint.activate([
            infoPanel.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            infoPanel.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            infoPanelBottomConstraint,
            
            infoPanelStack.topAnchor.constraint(equalTo: infoPanel.topAnchor, constant: 20),
            infoPanelStack.leadingAnchor.constraint(equalTo: infoPanel.leadingAnchor, constant: 20),
            infoPanelStack.trailingAnchor.constraint(equalTo: infoPanel.trailingAnchor, constant: -20),
            infoPanelStack.bottomAnchor.constraint(equalTo: infoPanel.safeAreaLayoutGuide.bottomAnchor, constant: -20)
        ])
    }
    
    private func showInfoPanel(for service: ServiceLocation) {
        selectedService = service
        
        infoPanelStack.arrangedSubviews.forEach { $0.removeFromSuperview() }
        
        // Handle indicator
        let handle = UIView()
        handle.backgroundColor = .systemGray4
        handle.layer.cornerRadius = 2.5
        handle.translatesAutoresizingMaskIntoConstraints = false
        handle.heightAnchor.constraint(equalToConstant: 5).isActive = true
        handle.widthAnchor.constraint(equalToConstant: 40).isActive = true
        
        let handleContainer = UIView()
        handleContainer.addSubview(handle)
        handle.centerXAnchor.constraint(equalTo: handleContainer.centerXAnchor).isActive = true
        handle.centerYAnchor.constraint(equalTo: handleContainer.centerYAnchor).isActive = true
        handleContainer.heightAnchor.constraint(equalToConstant: 10).isActive = true
        
        // Service info
        let titleRow = UIStackView()
        titleRow.axis = .horizontal
        titleRow.alignment = .center
        
        let icon = UIImageView(image: UIImage(systemName: service.imageSystemName))
        icon.tintColor = service.category.color
        icon.widthAnchor.constraint(equalToConstant: 40).isActive = true
        icon.heightAnchor.constraint(equalToConstant: 40).isActive = true
        
        let nameLabel = UILabel()
        nameLabel.text = service.name
        nameLabel.font = .systemFont(ofSize: 20, weight: .bold)
        
        let priceLabel = UILabel()
        priceLabel.text = service.formattedPrice
        priceLabel.font = .systemFont(ofSize: 20, weight: .bold)
        priceLabel.textColor = .systemGreen
        
        titleRow.addArrangedSubview(icon)
        titleRow.addArrangedSubview(UIView.spacer(width: 8))
        titleRow.addArrangedSubview(nameLabel)
        titleRow.addArrangedSubview(UIView())
        titleRow.addArrangedSubview(priceLabel)
        
        let descLabel = UILabel()
        descLabel.text = service.description
        descLabel.font = .systemFont(ofSize: 14)
        descLabel.textColor = .secondaryLabel
        descLabel.numberOfLines = 0
        
        let ratingLabel = UILabel()
        ratingLabel.text = "⭐ \(service.rating) • \(service.category.rawValue)"
        ratingLabel.font = .systemFont(ofSize: 13, weight: .medium)
        ratingLabel.textColor = .secondaryLabel
        
        // Buttons
        let buttonStack = UIStackView()
        buttonStack.axis = .horizontal
        buttonStack.spacing = 12
        buttonStack.distribution = .fillEqually
        
        let addToCartButton = UIButton(type: .system)
        addToCartButton.setTitle("Add to Cart", for: .normal)
        addToCartButton.titleLabel?.font = .systemFont(ofSize: 16, weight: .semibold)
        addToCartButton.setTitleColor(.white, for: .normal)
        addToCartButton.backgroundColor = .systemBlue
        addToCartButton.layer.cornerRadius = 12
        addToCartButton.heightAnchor.constraint(equalToConstant: 50).isActive = true
        addToCartButton.addTarget(self, action: #selector(addToCartTapped), for: .touchUpInside)
        
        let detailsButton = UIButton(type: .system)
        detailsButton.setTitle("Details", for: .normal)
        detailsButton.titleLabel?.font = .systemFont(ofSize: 16, weight: .semibold)
        detailsButton.setTitleColor(.systemBlue, for: .normal)
        detailsButton.backgroundColor = .systemBlue.withAlphaComponent(0.1)
        detailsButton.layer.cornerRadius = 12
        detailsButton.heightAnchor.constraint(equalToConstant: 50).isActive = true
        detailsButton.addTarget(self, action: #selector(detailsTapped), for: .touchUpInside)
        
        buttonStack.addArrangedSubview(detailsButton)
        buttonStack.addArrangedSubview(addToCartButton)
        
        infoPanelStack.addArrangedSubview(handleContainer)
        infoPanelStack.addArrangedSubview(titleRow)
        infoPanelStack.addArrangedSubview(ratingLabel)
        infoPanelStack.addArrangedSubview(descLabel)
        infoPanelStack.addArrangedSubview(buttonStack)
        
        view.layoutIfNeeded()
        infoPanelBottomConstraint.constant = 0
        UIView.animate(withDuration: 0.4, delay: 0, usingSpringWithDamping: 0.8, initialSpringVelocity: 0) {
            self.view.layoutIfNeeded()
        }
    }
    
    private func hideInfoPanel() {
        infoPanelBottomConstraint.constant = 300
        UIView.animate(withDuration: 0.3) {
            self.view.layoutIfNeeded()
        }
    }
    
    @objc private func addToCartTapped() {
        guard let service = selectedService else { return }
        CartManager.shared.addItem(service)
        
        let alert = UIAlertController(
            title: "Added to Cart! 🛒",
            message: "\(service.name) has been added.",
            preferredStyle: .alert
        )
        alert.addAction(UIAlertAction(title: "Continue", style: .default))
        alert.addAction(UIAlertAction(title: "View Cart", style: .default) { [weak self] _ in
            let vc = CartViewController()
            let nav = UINavigationController(rootViewController: vc)
            self?.present(nav, animated: true)
        })
        present(alert, animated: true)
    }
    
    @objc private func detailsTapped() {
        guard let service = selectedService else { return }
        let vc = ServiceDetailViewController(service: service)
        navigationController?.pushViewController(vc, animated: true)
    }
    
    // MARK: - GMSMapViewDelegate
    
    func mapView(_ mapView: GMSMapView, didTap marker: GMSMarker) -> Bool {
        if let service = marker.userData as? ServiceLocation {
            showInfoPanel(for: service)
            
            let camera = GMSCameraPosition.camera(
                withTarget: service.coordinate,
                zoom: 15
            )
            mapView.animate(to: camera)
        }
        return true
    }
    
    func mapView(_ mapView: GMSMapView, didTapAt coordinate: CLLocationCoordinate2D) {
        hideInfoPanel()
    }
    
    private var mapStyleJSON: String {
        """
        [
          {
            "featureType": "poi.business",
            "stylers": [{"visibility": "off"}]
          },
          {
            "featureType": "transit",
            "elementType": "labels.icon",
            "stylers": [{"visibility": "off"}]
          }
        ]
        """
    }
}

extension UIView {
    static func spacer(width: CGFloat? = nil, height: CGFloat? = nil) -> UIView {
        let view = UIView()
        if let w = width {
            view.widthAnchor.constraint(equalToConstant: w).isActive = true
        }
        if let h = height {
            view.heightAnchor.constraint(equalToConstant: h).isActive = true
        }
        return view
    }
}


