// --- File: CartViewController.swift ---

import UIKit

class CartViewController: UIViewController, UITableViewDataSource, UITableViewDelegate {
    
    private let tableView = UITableView(frame: .zero, style: .insetGrouped)
    private let checkoutButton = UIButton(type: .system)
    private let totalLabel = UILabel()
    private let emptyLabel = UILabel()
    
    override func viewDidLoad() {
        super.viewDidLoad()
        title = "Cart"
        view.backgroundColor = .systemBackground
        
        navigationItem.leftBarButtonItem = UIBarButtonItem(
            barButtonSystemItem: .close,
            target: self,
            action: #selector(dismiss(_:))
        )
        
        setupUI()
        updateUI()
        
        NotificationCenter.default.addObserver(
            self, selector: #selector(cartUpdated),
            name: .cartUpdated, object: nil
        )
    }
    
    private func setupUI() {
        tableView.dataSource = self
        tableView.delegate = self
        tableView.register(CartItemCell.self, forCellReuseIdentifier: "CartCell")
        tableView.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(tableView)
        
        // Bottom bar
        let bottomBar = UIView()
        bottomBar.backgroundColor = .systemBackground
        bottomBar.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(bottomBar)
        
        let topBorder = UIView()
        topBorder.backgroundColor = .separator
        topBorder.translatesAutoresizingMaskIntoConstraints = false
        bottomBar.addSubview(topBorder)
        
        totalLabel.font = .systemFont(ofSize: 20, weight: .bold)
        totalLabel.translatesAutoresizingMaskIntoConstraints = false
        bottomBar.addSubview(totalLabel)
        
        checkoutButton.setTitle("Checkout", for: .normal)
        checkoutButton.titleLabel?.font = .systemFont(ofSize: 18, weight: .bold)
        checkoutButton.setTitleColor(.white, for: .normal)
        checkoutButton.backgroundColor = .systemGreen
        checkoutButton.layer.cornerRadius = 14
        checkoutButton.translatesAutoresizingMaskIntoConstraints = false
        checkoutButton.addTarget(self, action: #selector(checkout), for: .touchUpInside)
        bottomBar.addSubview(checkoutButton)
        
        emptyLabel.text = "Your cart is empty 🛒"
        emptyLabel.font = .systemFont(ofSize: 20, weight: .medium)
        emptyLabel.textColor = .secondaryLabel
        emptyLabel.textAlignment = .center
        emptyLabel.translatesAutoresizingMaskIntoConstraints = false
        view.addSubview(emptyLabel)
        
        NSLayoutConstraint.activate([
            tableView.topAnchor.constraint(equalTo: view.safeAreaLayoutGuide.topAnchor),
            tableView.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            tableView.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            tableView.bottomAnchor.constraint(equalTo: bottomBar.topAnchor),
            
            bottomBar.leadingAnchor.constraint(equalTo: view.leadingAnchor),
            bottomBar.trailingAnchor.constraint(equalTo: view.trailingAnchor),
            bottomBar.bottomAnchor.constraint(equalTo: view.safeAreaLayoutGuide.bottomAnchor),
            bottomBar.heightAnchor.constraint(equalToConstant: 120),
            
            topBorder.topAnchor.constraint(equalTo: bottomBar.topAnchor),
            topBorder.leadingAnchor.constraint(equalTo: bottomBar.leadingAnchor),
            topBorder.trailingAnchor.constraint(equalTo: bottomBar.trailingAnchor),
            topBorder.heightAnchor.constraint(equalToConstant: 0.5),
            
            totalLabel.topAnchor.constraint(equalTo: bottomBar.topAnchor, constant: 16),
            totalLabel.leadingAnchor.constraint(equalTo: bottomBar.leadingAnchor, constant: 20),
            totalLabel.trailingAnchor.constraint(equalTo: bottomBar.trailingAnchor, constant: -20),
            
            checkoutButton.topAnchor.constraint(equalTo: totalLabel.bottomAnchor, constant: 12),
            checkoutButton.leadingAnchor.constraint(equalTo: bottomBar.leadingAnchor, constant: 20),
            checkoutButton.trailingAnchor.constraint(equalTo: bottomBar.trailingAnchor, constant: -20),
            checkoutButton.heightAnchor.constraint(equalToConstant: 52),
            
            emptyLabel.centerXAnchor.constraint(equalTo: view.centerXAnchor),
            emptyLabel.centerYAnchor.constraint(equalTo: view.centerYAnchor, constant: -40)
        ])
    }
    
    private func updateUI() {
        let isEmpty = CartManager.shared.items.isEmpty
        emptyLabel.isHidden = !isEmpty
        tableView.isHidden = isEmpty
        checkoutButton.isEnabled = !isEmpty
        checkoutButton.alpha = isEmpty ? 0.5 : 1.0
        
        totalLabel.text = "Total: \(CartManager.shared.formattedTotal)"
        tableView.reloadData()
    }
    
    @objc private func cartUpdated() {
        updateUI()
    }
    
    @objc private func dismiss(_ sender: Any) {
        dismiss(animated: true)
    }
    
    @objc private func checkout() {
        let vc = CheckoutViewController()
        navigationController?.pushViewController(vc, animated: true)
    }
    
    // MARK: - TableView
    
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        CartManager.shared.items.count
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "CartCell", for: indexPath) as! CartItemCell
        let item = CartManager.shared.items[indexPath.row]
        cell.configure(with: item)
        cell.onQuantityChange = { [weak self] increment in
            if increment {
                CartManager.shared.addItem(item.service)
            } else {
                CartManager.shared.removeItem(item.service)
            }
            self?.updateUI()
        }
        return cell
    }
    
    func tableView(_ tableView: UITableView, heightForRowAt indexPath: IndexPath) -> CGFloat {
        80
    }
    
    func tableView(_ tableView: UITableView, commit editingStyle: UITableViewCell.EditingStyle, forRowAt indexPath: IndexPath) {
        if editingStyle == .delete {
            let item = CartManager.shared.items[indexPath.row]
            for _ in 0..<item.quantity {
                CartManager.shared.removeItem(item.service)
            }
            updateUI()
        }
    }
}


